<?php require "conn.php"; $UserLat=0; $UserLongt=0; $Pro="Normal"; $Page=0; $t1 = microtime(true); $res = mysqli_query($con,"SELECT Shops.*, Posts.*, Foods.*, (6372.797 * acos(cos(radians($UserLat)) * cos(radians(ShopLat)) * cos(radians(ShopLongt) - radians($UserLongt)) + sin(radians($UserLat)) * sin(radians(ShopLat)))) AS distance FROM Shops JOIN Posts ON Shops.ShopID=Posts.ShopID LEFT JOIN Foods ON Posts.ProductID = Foods.FoodID JOIN Categories ON Shops.CategoryID = Categories.CategoryId WHERE Shops.Status = 'ACTIVE' AND Categories.Pro = '$Pro' AND Posts.PostStatus='ACTIVE' AND (Posts.Video IS NULL OR Posts.Video = '' OR Posts.Video = '0' OR Posts.Video = 'NONE') HAVING distance <= 10050 ORDER BY distance ASC, (Posts.PostLikes * 2 + Posts.Postcomments * 3) DESC, rand() LIMIT $Page, 5"); if(!$res) echo mysqli_error($con); else echo mysqli_num_rows($res)." rows in ".(microtime(true)-$t1)."s\n"; ?>
